import React from 'react';
import './Testimonial.css';

const leftAvatars = [
  { img: 'https://randomuser.me/api/portraits/men/41.jpg' },
  { img: 'https://randomuser.me/api/portraits/women/65.jpg' },
  { img: 'https://randomuser.me/api/portraits/men/36.jpg' },
];

const rightAvatars = [
  { img: 'https://randomuser.me/api/portraits/men/52.jpg' },
  { img: 'https://randomuser.me/api/portraits/men/71.jpg', label: 'Aswani' },
];

const Testimonial = () => {
  return (
    <section className="testimonial">
      {/* Left column avatars */}
      <div className="testimonial__col testimonial__col--left">
        {leftAvatars.map((a, i) => (
          <div key={i} className="testimonial__av">
            <img src={a.img} alt="reviewer" />
          </div>
        ))}
      </div>

      {/* Center card */}
      <div className="testimonial__center">
        <div className="testimonial__card">
          <p className="testimonial__card-label">
            What our customer<br />says About Us
          </p>
          <div className="testimonial__quotes">
            <span className="testimonial__q testimonial__q--open">"</span>
            <p className="testimonial__body">
              Elementum delivered the site with infirm timeline as they requested.
              Infirm end, the client found a 50% increase in traffic with in days
              since its launch. They also had an impressive ability to use technologies
              that the company hasn't used, which have also proved to be easy to
              use and reliable.
            </p>
            <span className="testimonial__q testimonial__q--close">"</span>
          </div>
        </div>
      </div>

      {/* Right column avatars */}
      <div className="testimonial__col testimonial__col--right">
        {rightAvatars.map((a, i) => (
          <div key={i} className="testimonial__av-wrap">
            {a.label && (
              <span className="testimonial__name-tag">{a.label}</span>
            )}
            <div className="testimonial__av">
              <img src={a.img} alt="reviewer" />
            </div>
          </div>
        ))}
      </div>
    </section>
  );
};

export default Testimonial;
